/**
 * Session Heartbeat — PostToolUse hook (M168 Phase 2, #1912)
 *
 * Updates sessions.last_heartbeat for the current sid on every PostToolUse,
 * rate-limited to once per 5 seconds via a module-level cache. Keeps the
 * DB pressure bounded — even a hot tool-use loop touches at most one row
 * per session every 5s.
 *
 * No-op when the session row doesn't exist yet (race vs SessionStart).
 * UPDATE is a no-op in that case; we let the next heartbeat retry.
 *
 * Hook event: PostToolUse (async, timeout: 3s, matcher: catchall).
 */

import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';
import { writeWithRetry } from '../lib/session-registry.js';

const HOOK_NAME = 'posttool/heartbeat';
const RATE_LIMIT_MS = 5_000;

// Module-level cache: last heartbeat timestamp (ms) per sid.
const lastBeat = new Map<string, number>();

export function heartbeat(
  input: HookInput,
  ctx: HookContext = NOOP_CTX,
): HookResult {
  const sid = input.session_id;
  if (!sid) return outputSilentSuccess();

  const nowMs = Date.now();
  const prev = lastBeat.get(sid) ?? 0;
  if (nowMs - prev < RATE_LIMIT_MS) {
    return outputSilentSuccess();
  }
  lastBeat.set(sid, nowMs);

  const nowSec = Math.floor(nowMs / 1000);
  try {
    writeWithRetry(db => {
      db.prepare(
        `UPDATE sessions SET last_heartbeat = ? WHERE sid = ?`,
      ).run(nowSec, sid);
    });
  } catch (err) {
    ctx.log(HOOK_NAME, `heartbeat failed: ${(err as Error).message}`);
  }

  return outputSilentSuccess();
}

/** Exposed for tests. */
export const __internals = { lastBeat, RATE_LIMIT_MS };
